var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"어쩌지……? 이런 디자인일 줄은 생각 못 했는데…….","JPN":"どうしよう……？　こんなデザインは予想してなかったけど……","ENG":"What do I do...? I didn't know my outfit would be in this design...","TWN":"怎麼辦……？沒想到會是這樣的設計……"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"나중에 학생들 앞에서 이 모습은 조금 민망하달까…….","JPN":"生徒たちの前でこんな姿はちょっと恥ずかしいかな……","ENG":"I don't think I'll be able to show this to our students...","TWN":"在學生面前穿這樣有點丟人吧……"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그런가요? 제가 보기엔 단정하고 성숙하다는 느낌입니다만…….","JPN":"そうですか？　私が見るには端正で成熟な感じがしますけど……","ENG":"Is that so? I personally think it looks clean and mature...","TWN":"會嗎？我覺得很成熟端莊……"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"정 불편하시다면 제가 친구분께 연락해 볼까요?","JPN":"そんなに気まずいなら、私からご友人の方に連絡してみましょうか？","ENG":"If you feel uncomfortable in it, should I try contacting your friend?","TWN":"理事長覺得不妥的話，還是我跟對方聯絡一下？"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"아냐. 그럴 필요까진 없어.","JPN":"ううん。そこまでする必要はないわ。","ENG":"No, there's no need for that.","TWN":"沒關係，不用打給她。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"장난으로 그렸던 건데……. 기억해 주었구나.","JPN":"半分いたずらで描いたんだけど……覚えていてくれたんだね。","ENG":"I drew it for fun, but... she remembered.","TWN":"我只是無聊畫的……沒想到她還記得。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"저번에 전달받기론, 이사장님이 희망했던 복장이라 하시더군요.","JPN":"この前、理事長のご希望の服装だと聞きました。","ENG":"From what I have been told last time, it is an outfit that you wanted to wear.","TWN":"上次聽對方說，這是理事長希望的造型呢。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"후후, 그렇겠지. 하여간 장난이 심하다니까. ","JPN":"ふふ、そうよね。まったく悪ふざけがすぎるんだから。 ","ENG":"Ha ha, I'm sure it is. I knew she couldn't help not pull a prank.","TWN":"呵呵，我就知道，還真會開玩笑。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"일단 혼자 진행하고 있을게. 옌도 잘 지켜봐 주렴.","JPN":"とりあえず一人で進めているわね。イェンさんもちゃんと見守っててちょうだい。","ENG":"I'll proceed on my own for now. Yen, keep monitoring me.","TWN":"總之，我就先自己玩，你先在一旁看著。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"네. 알겠습니다.","JPN":"はい。承知しました。","ENG":"Yes. Understood.","TWN":"好的，理事長。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"음……. 일단 이 필드는 시안에서 공유받은 그대로네.","JPN":"うーん……まずこのフィールドは試案で共有してもらったままね。","ENG":"Mm... The field is just as the design that was shared with us.","TWN":"嗯……目前看一下來，地圖長得跟收到的設計圖差不多。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"기존에 사용했던 리소스와는 비교도 안 될 퀄리티인걸?","JPN":"前に使っていたリソースとは比べ物にならないクオリティーだわ。","ENG":"The quality is incomparable to the resources used previously.","TWN":"品質和之前用過的素材完全沒得比呢。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"휴……. 그나저나 이래선 오늘 안에 다 못 볼지도 모르겠어.","JPN":"ふう……それにしても、これじゃあ今日中に全部見て回るのは不可能かもしれない。","ENG":"Phew... I don't think I'll be able to check the entire thing by today.","TWN":"呼……但這樣今天應該很難全部看完吧？"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"어머? 저건…!","JPN":"あら？　あれは……！","ENG":"Oh? That's...!","TWN":"嗯？那是…！"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"저건 분명… 내가 옛날에 디자인한 귀염둥이잖아!","JPN":"あれは確か……私が昔デザインしたかわいい子じゃない！","ENG":"That's... Cutie! I designed it a long time ago!","TWN":"那不是…我以前設計的小可愛嗎！"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"그리워라… 한번 가까이 가봐야지!","JPN":"懐かしい……一度近づいてみよう！","ENG":"Oh, how I missed you... I got to see you up close!","TWN":"好懷念喔…我要靠近一點看！"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"와~ 가까이서 보니까 더 굉장하잖아?","JPN":"わあ～近くで見るともっとすごいわね！","ENG":"Wow...! It's more incredible looking at it up close!","TWN":"哇～近看更不得了欸？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"그렇지 그렇지. 변이된 물고기 컨셉이니까, 아가미가 없어야 고증에 맞지.","JPN":"そう、そう。変異した魚コンセプトだから、エラがなくて正解なの。","ENG":"Yes, that's right. Since it's a mutated fish, it shouldn't have any gills.","TWN":"沒錯，它的設計概念是變種魚，沒有魚鰓才是對的！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"상어의 피부와 근육도 완벽하게 구현했네?","JPN":"サメの肌と筋肉も完璧に具現化されてるじゃない。","ENG":"Even the shark's skin and muscles are perfectly implemented!","TWN":"鯊魚的皮膚和肌肉也完美呈現呢。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"정글이란 환경에 맞게끔 피부톤에도 변화를 주는 게 더 좋았을 텐데…….","JPN":"ジャングルという環境に合わせて、肌のトーンも変化させたらもっとよかったかな……","ENG":"It would've been better to change the skin tone to match the jungle environment, however...","TWN":"要是膚色可以配合叢林的環境而變化就更好了……"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"잠깐, 여긴 어디지? 홀린 듯이 이런 곳까지 와버렸네…….","JPN":"ちょっと、ここはどこ？　いつの間にこんなところまで来ちゃったの……","ENG":"Wait, where am I? I was so focused on seeing it that I don't know where I am...","TWN":"等等，這是什麼地方？迷迷糊糊就走到這來了……"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"후훗, 그래도 내가 그렸던 몬스터를 직접 눈앞에서 보게 되는 날이 오다니…….","JPN":"ふふっ、でも私が描いたモンスターを直接目の前で見る日が来るなんて……","ENG":"Ha ha. But it feels great to see my creation come to life right before my eyes–","TWN":"呵呵，不過真沒想到會有這麼一天，我畫的怪物竟然就出現在我眼前……"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"엇?!","JPN":"あっ！？","ENG":"Wha?!","TWN":"嗯？！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NPC","text":{"KOREA":"하아아아아아앗……!! 간데이! 파이어 블레이드으으으으으으!!","JPN":"はああああああっ……！！　行くぞ！　ファイアブレイドおおおぉぉぉ！！","ENG":"Haaaaah...! Fire Blade comin’ through!","TWN":"啊啊啊啊啊……！去唄，火焰劍～～～！！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NPC","text":{"KOREA":"아하하, 이 기술은 이젠 좀 부끄럽네.","JPN":"あはは、もうこの技はちょっと恥ずかしいな。","ENG":"Ah hah hah! Sayin' that skill name got old quick.","TWN":"哈哈哈，現在用這招感覺有點羞恥呢。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};